+      limit,
+      excludeProductIds,
+      baseUrl,
+      enabled,
+      imageDesignCid,
+    });
+
+    React.useEffect(() => {
+      if (isError) onError?.();
+    }, [isError, onError]);
+
+    return <ProductsCarouselWidget ref={ref} products={products} isLoading={isLoading} {...widgetProps} />;
+  },
+);
