import { formatPrice, formatRatingCount, formatRatingScore } from './utils';
import type { UnitPrice } from './types';

describe('formatPrice', () => {
  it('returns null for empty prices array', () => {
    expect(formatPrice([], 25)).toBeNull();
  });

  it('returns amount and suffix for the matching quantity', () => {
    const prices: UnitPrice[] = [
      { quantity: 12, price: 11.95 },
      { quantity: 25, price: 9.5 },
    ];
    expect(formatPrice(prices, 25)).toEqual({ amount: '$9.50', suffix: '/ea for 25 items' });
  });

  it('falls back to first entry when quoteQty has no match', () => {
    const prices: UnitPrice[] = [{ quantity: 6, price: 14.0 }];
    expect(formatPrice(prices, 100)).toEqual({ amount: '$14.00', suffix: '/ea for 6 items' });
  });

  it('does not include originalAmount when there is no discount', () => {
    const prices: UnitPrice[] = [{ quantity: 25, price: 9.5 }];
    const result = formatPrice(prices, 25);
    expect(result?.originalAmount).toBeUndefined();
  });

  it('does not include originalAmount when regularPrice equals price', () => {
    const prices: UnitPrice[] = [{ quantity: 25, price: 9.5, regularPrice: 9.5 }];
    const result = formatPrice(prices, 25);
    expect(result?.originalAmount).toBeUndefined();
  });

  it('includes originalAmount when regularPrice is greater than price', () => {
    const prices: UnitPrice[] = [{ quantity: 25, price: 8.07, regularPrice: 9.5 }];
    expect(formatPrice(prices, 25)).toEqual({
      amount: '$8.07',
      suffix: '/ea for 25 items',
      originalAmount: '$9.50',
    });
  });

  it('uses the discounted entry when quoteQty matches a discounted price', () => {
    const prices: UnitPrice[] = [
      { quantity: 12, price: 10.0, regularPrice: 12.0 },
      { quantity: 25, price: 8.0 },
    ];
    expect(formatPrice(prices, 12)).toEqual({
      amount: '$10.00',
      suffix: '/ea for 12 items',
      originalAmount: '$12.00',
    });
  });
});

describe('formatRatingScore', () => {
  it('formats score to one decimal', () => {
    expect(formatRatingScore(4.678)).toBe('4.7');
  });

  it('clamps scores below 1 to 1.0', () => {
    expect(formatRatingScore(0)).toBe('1.0');
    expect(formatRatingScore(0.5)).toBe('1.0');
  });
});

describe('formatRatingCount', () => {
  it('formats count with parentheses', () => {
    expect(formatRatingCount(448)).toBe('(448)');
  });

  it('caps at 10,000 with + suffix', () => {
    expect(formatRatingCount(13135)).toBe('(10,000+)');
  });

  it('returns null for NaN', () => {
    expect(formatRatingCount(NaN)).toBeNull();
  });
});
